INSERT INTO training_records (employee_id, training_type_id, completion_date, source, pass_fail, reviewed_by)
SELECT e.id, sr.training_type_id, sr.completion_date, 'signin', sr.pass_fail, sr.reviewed_by
FROM source_rows sr
JOIN employees e ON (
  (lower(e.last_name) = lower(sr.last_name) AND lower(e.first_name) = lower(sr.first_name))
  OR e.aliases @> ARRAY[sr.full_name]::text[]
)
ON CONFLICT (employee_id, training_type_id, completion_date) DO NOTHING;